fun solve(nums: Array<Long>, k: Long): Long {
    val N = nums.size
    // Use a sufficiently large long value for infinity
    val INF: Long = Long.MAX_VALUE / 2 // Use half to prevent overflow during addition

    if (k == 0L) return 0L

    // Maximum possible number of non-adjacent peaks in a circle is N/2
    if (k > N / 2) return -1L

    // 1. Precalculate costs C_i: minimum cost to make nums[i] a peak based on original neighbors
    val C = LongArray(N)
    for (i in 0 until N) {
        // Neighbors in circular array
        val L_i = nums[(i - 1 + N) % N]
        val R_i = nums[(i + 1) % N]

        // Required value must be strictly greater than both neighbors: max(L_i, R_i) + 1
        val required_val = maxOf(L_i, R_i) + 1

        // Cost = max(0, required_val - nums[i])
        var cost = 0L
        if (required_val > nums[i]) {
            cost = required_val - nums[i]
        }
        C[i] = cost
    }

    // Helper function for Path DP
    // Calculates min cost to achieve k_target non-adjacent peaks in indices [start, end]
    // Returns INF if impossible.
    fun pathDP(start: Int, end: Int, k_target: Int): Long {
        if (k_target < 0) return INF

        val M = end - start + 1 // Length of the path segment
        if (M <= 0) return if (k_target == 0) 0L else INF

        if (k_target > M / 2) return INF
        if (k_target == 0) return 0L

        // DP[m][j][s]
        // m: length prefix (1 to M)
        // j: number of peaks achieved (0 to k_target)
        // s: state of the last element (index start + m - 1)
        // s=0: not chosen, s=1: chosen

        // DP table size: (M+1) x (k_target+1) x 2
        val DP = Array(M + 1) { 
            Array(k_target + 1) { 
                LongArray(2) { INF } 
            }
        }

        // Base case: m=1 (Index start)
        val i0 = start
        DP[1][0][0] = 0L // Not chosen
        DP[1][1][1] = C[i0] // Chosen

        // Fill DP table
        for (m in 2..M) {
            val i = start + m - 1 // Current index (absolute index)

            for (j in 0..k_target) {

                // State s=0: i is NOT chosen
                // Transition from i-1 (m-1) being chosen or not chosen
                DP[m][j][0] = minOf(DP[m - 1][j][0], DP[m - 1][j][1])

                // State s=1: i IS chosen (Requires j >= 1)
                if (j >= 1) {
                    // Must transition from i-1 (m-1) NOT chosen (no adjacent peaks)
                    val prev_cost = DP[m - 1][j - 1][0]
                    if (prev_cost != INF) {
                        DP[m][j][1] = prev_cost + C[i]
                    }
                }
            }
        }

        return minOf(DP[M][k_target][0], DP[M][k_target][1])
    }

    var min_cost: Long = INF

    // Case 1: Index 0 is NOT a peak. Solve on path [1, N-1] for k peaks.
    if (N > 1) {
        val cost1 = pathDP(1, N - 1, k.toInt())
        min_cost = minOf(min_cost, cost1)
    } else if (N == 1) {
         // N >= 2 based on constraints, but handled defensively
    }

    // Case 2: Index 0 IS a peak. Solve on path [2, N-2] for k-1 peaks.
    if (k >= 1L) {
        val k_target_2 = (k - 1).toInt()
        val start2 = 2
        val end2 = N - 2

        var cost2_path = INF
        if (start2 > end2) {
            // Empty path case (e.g., N=2 or N=3). Must require 0 peaks.
            cost2_path = if (k_target_2 == 0) 0L else INF
        } else {
            // Standard path DP for internal indices
            cost2_path = pathDP(start2, end2, k_target_2)
        }

        if (cost2_path != INF) {
             val cost2 = C[0] + cost2_path
             min_cost = minOf(min_cost, cost2)
        }
    }

    return if (min_cost == INF) -1L else min_cost
}

